import { NextResponse } from "next/server";
import bcrypt from "bcryptjs";
import { prisma } from "@/lib/prisma";

import { getSettings } from "@/app/[locale]/admin/settings/actions";

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { 
      name, email, password, phone, gender, role,
      specializations, yearsExperience, pricePerSession, salaryType,
      country, countryCode, currency
    } = body as {
      name: string;
      email: string;
      password: string;
      phone?: string;
      gender?: string;
      role?: string;
      specializations?: string;
      yearsExperience?: string;
      pricePerSession?: string;
      salaryType?: "FIXED" | "COMMISSION";
      country?: string;
      countryCode?: string;
      currency?: string;
    };

    if (!name || !email || !password) {
      return NextResponse.json(
        { error: "جميع الحقول مطلوبة" },
        { status: 400 }
      );
    }

    // التحقق من قوة كلمة المرور (8 أحرف على الأقل، تحتوي على حرف ورقم)
    const hasLetter = /[a-zA-Z\u0600-\u06FF]/.test(password);
    const hasNumber = /\d/.test(password);
    if (password.length < 8 || !hasLetter || !hasNumber) {
      return NextResponse.json(
        { error: "يجب أن تتكون كلمة المرور من 8 أحرف على الأقل، وتحتوي على حرف واحد ورقم واحد على الأقل." },
        { status: 400 }
      );
    }

    const existing = await prisma.user.findUnique({ where: { email } });
    if (existing) {
      return NextResponse.json(
        { error: "البريد الإلكتروني مسجل مسبقاً" },
        { status: 400 }
      );
    }

    const hashedPassword = await bcrypt.hash(password, 12);
    const userRole = role === "THERAPIST" ? "THERAPIST" : "PATIENT";

    // التحقق من إعدادات المنصة
    const settings = await getSettings();
    if (userRole === "THERAPIST" && !settings.allowNewTherapists) {
      return NextResponse.json(
        { error: "تسجيل الأخصائيين الجدد معطل حالياً من قبل الإدارة" },
        { status: 400 }
      );
    }
    if (userRole === "PATIENT" && !settings.allowNewPatients) {
      return NextResponse.json(
        { error: "تسجيل المرضى الجدد معطل حالياً من قبل الإدارة" },
        { status: 400 }
      );
    }

    const user = await prisma.user.create({
      data: {
        name,
        email,
        password: hashedPassword,
        phone,
        country: country || "Egypt",
        countryCode: countryCode || "+20",
        currency: currency || "EGP",
        gender,
        role: userRole,
        ...(userRole === "THERAPIST" && {
          therapistProfile: {
            create: {
              bio: "أخصائي نفسي جديد",
              specializations: specializations ? JSON.stringify(specializations.split(',').map(s => s.trim())) : JSON.stringify(["استشارات عامة"]),
              pricePerSession: (salaryType === "FIXED" || !pricePerSession) ? 300 : Number(pricePerSession),
              yearsExperience: yearsExperience ? Number(yearsExperience) : 1,
              salaryType: salaryType === "FIXED" ? "FIXED" : "COMMISSION",
            },
          },
        }),
      },
    });

    return NextResponse.json(
      { id: user.id, email: user.email, role: user.role },
      { status: 201 }
    );
  } catch (error) {
    console.error("Registration error:", error);
    return NextResponse.json(
      { error: "حدث خطأ أثناء التسجيل" },
      { status: 500 }
    );
  }
}
